import subprocess
import sys

def scan_bluetooth():
    devices = []
    try:
        result = subprocess.run(['hcitool', 'scan', '--length=10'], capture_output=True, text=True, timeout=30)
        for line in result.stdout.strip().split('\n')[1:]:
            parts = line.strip().split('\t')
            if len(parts) >= 2:
                devices.append({'address': parts[0], 'name': parts[1] if len(parts) > 1 else 'Unknown'})
    except FileNotFoundError:
        try:
            result = subprocess.run(['bluetoothctl', 'devices'], capture_output=True, text=True, timeout=15)
            for line in result.stdout.strip().split('\n'):
                parts = line.split()
                if len(parts) >= 3:
                    devices.append({'address': parts[1], 'name': ' '.join(parts[2:])})
        except: pass
    return devices

print('=== Bluetooth Scanner ===')
devices = scan_bluetooth()
print(f'Devices: {len(devices)}')
for d in devices:
    print(f'  {d["address"]:18s} {d["name"]}')
